raw = json.loads(RAW.read_text(encoding='utf-8'))
out = []
missing = []
for p in raw['products']:
    pid = p['product_id']
    a = A.get(pid)
    if not a:
        missing.append(pid); continue
    out.append({
        "source": "robotsasia",
        "source_url": p.get('sourceUrl') or p.get('url'),
        "source_price_raw": p.get('priceRaw') or None,
        "product_id": pid,
        "slug": pid,
        "category": p['category'],
        "subcategory": p.get('subcategory') or None,
        "brand": a['brand'],
        "model": a['model'],
        "origin_fa": "چین",
        "origin_en": "China",
        "product_name_fa": a['name_fa'],
        "product_name_en": a['name_en'],
        "tagline_fa": a['tagline_fa'],
        "tagline_en": a['tagline_en'],
        "description_fa": a['desc_fa'],
        "description_en": a['desc_en'],
        "lead_time_days": 45,
        "hero_image": p.get('ogImage') or "",
        "specs": a['specs'],
        "use_cases": a.get('use_cases', []),
    })

assert not missing, f"authored content missing for: {missing}"
doc = {"_meta": {"source": "robotsasia", "scope": "Core-4 test batch (humanoids/quadrupeds/amrs/drones), standalone robots only",
        "note": "Paraphrased IranRobot copy, factual specs. Source CNY prices kept in source_price_raw; catalog stays quote-based. education use_case tagged on clearly educational/research units."},
       "products": out}
OUT.write_text(json.dumps(doc, ensure_ascii=False, indent=2), encoding='utf-8')
from collections import Counter
print("wrote", OUT, "with", len(out), "products")
print("by category:", dict(Counter(p['category'] for p in out)))
print("with use_cases=education:", sum(1 for p in out if 'education' in p['use_cases']))
